var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"다시 말해, 멋대로 소원구슬을 써먹고 껍데기만 가져왔다는 거군요.","JPN":"つまり、勝手に願い玉を使って抜け殻状態にしたものだけ持ってきたということですね。","ENG":"In other words, you used up the Wishing Ball without permission and brought its empty shell.","TWN":"所以，是徐芸擅自用了許願珠，然後只拿回來了一個空殼子。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이 요망한 도둑고양이가!","JPN":"このずうずうしい泥棒猫！","ENG":"You sneaky stray cat!","TWN":"這個奸詐的野貓！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"이를 어쩌죠, 부사장님? 전 기억이 하~나도 안 나는데요?","JPN":"どうしましょう、副社長？　私はぜーんぜんなーんにも思い出せません。","ENG":"Sorry, Vice President. I can't remember A SINGLE thing.","TWN":"什麼啊，副總？我完~全記不起來了呢？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"스카이라고 했나요. 참 신기하고 유용한 능력이네요.","JPN":"スカイって言いましたっけ？　本当に不思議で有用な能力ですね。","ENG":"That girl, Sky? What a mysterious yet useful ability she has.","TWN":"絲凱嗎？真是既神奇又有用的能力啊。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"불필요한 기억까지 깨끗이 지워 준다니 말이죠.","JPN":"不要な記憶まできれいさっぱり消してくれるなんて。","ENG":"She completely wiped out any unnecessary memories.","TWN":"連不必要的記憶都能清除乾淨。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"두통약...... 두통약이 필요해......","JPN":"頭痛薬……頭痛薬が必要よ……","ENG":"Pills... I need pills for my headache...","TWN":"止痛藥……我需要止痛藥……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"재미있군. 상시적인 인식 저해 능력이라니.","JPN":"面白いな。常時的な認識阻害能力か。","ENG":"Interesting. Disrupting other people's perception all the time...","TWN":"真有趣，居然有常態性的認知阻礙能力。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"과거에도 찾아보기 힘든 희귀하고 강력한 능력이야.","JPN":"過去の事例でも見かけない、珍しくて強力な能力だ。","ENG":"That's a very rare and powerful ability without precedent.","TWN":"那可是很罕見的強大能力呢。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서 자네가 제안한 마지막 소원은 대체 뭐였나?","JPN":"それで君が提案した最後の願いはいったい何だったんだ？","ENG":"So what was the last wish you suggested?","TWN":"所以，你提議的最後願望到底是什麼？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 시점에서 소원구슬의 힘은 거의 사라져서 스카이라는 학생의 문제를 완전히 고치기엔 부족했을 텐데?","JPN":"あの時点で願い玉の力はほとんど無くなって、\\nスカイという子の問題を完全に解決するには足りなかったはずだが。","ENG":"The remaining power of the Wishing Ball must have been insufficient to solve Sky's problem.","TWN":"那時許願珠的力量幾乎已經耗盡了，完全解決那個叫絲凱的學生的問題應該不夠吧？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"일이 끝나고 스카이에게 전해 들었어. 정말 기발한 방법이었지.","JPN":"仕事が終わってからスカイから聞いたの。本当に奇抜な方法だったわ。","ENG":"Sky told me after everything was over. It was a brilliant idea.","TWN":"事情結束後我聽絲凱說了，真的是一個很奇妙的方法。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"서윤은 그걸 기억하지 못할 테니까 내가 말해줄게.","JPN":"シズカはそれを覚えていないから、私から話してあげるわね。","ENG":"Since Seo Yoon doesn't remember it, I'll tell you what happened.","TWN":"徐芸應該不記得了，我來說吧。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그러니까, 그게 뭐였냐면......","JPN":"だから、それはつまり……","ENG":"Their wish was...","TWN":"那個，方法就是……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TEACHER_EXTRA_F_NULL","text":{"KOREA":"자, 오늘 수업은 여기까지!","JPN":"じゃあ、今日の授業はここまで！","ENG":"Okay, that's it for today!","TWN":"好了，今天的課就到這裡了！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TEACHER_EXTRA_F_NULL","text":{"KOREA":"돌아갈 때는 다들 빗길 조심하렴.","JPN":"帰る時はみんな雨道に気を付けようね。","ENG":"It's raining outside. Be careful on the slippery roads.","TWN":"回去時大家小心雨路濕滑。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHILDREN_EXTRA_NULL_NULL","text":{"KOREA":"고맙습니다, 선생님!","JPN":"ありがとうございました、先生！","ENG":"Thank you, ma'am!","TWN":"謝謝老師！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_CHILD"},{"id":"L27_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"고맙습니다, 선생님!","JPN":"ありがとうございました、先生！","ENG":"Thank you, ma'am!","TWN":"謝謝老師！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"우와...... 비 엄청 내린다......","JPN":"うわぁ……すごい雨……","ENG":"Whoa... It's raining a lot...","TWN":"哇啊……雨下得好大啊……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"망했다. 우산 안 가지고 왔는데......","JPN":"しまった。傘を持ってきてないよ。","ENG":"Ugh. I didn't bring my umbrella...","TWN":"完蛋了，我沒帶雨傘……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"그래? 내 우산 빌려 줄까?","JPN":"そう？　私の傘を貸してあげようか？","ENG":"Really? Want to borrow mine?","TWN":"是嗎？把我的雨傘借給你吧？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"야, 그냥 가방으로 가리고 정거장까지만 가자.","JPN":"ねえ、カバンを頭に乗っけて駅まで走ろう。","ENG":"Hey, let's just run to the bus stop.","TWN":"喂，就用書包擋著走到公車站吧。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"에이, 너 저번에도 그러다 쫄딱 젖어서 그냥 걸어갔잖아.","JPN":"ええーこの前もそれでびしょ濡れになったでしょ。","ENG":"Last time you did that, you got soaked to the bone and walked all the way home.","TWN":"唉，你上次不也那麼淋著雨走過去的嘛。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"스카이!","JPN":"スカイ！","ENG":"Sky!","TWN":"絲凱！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"아, 케이시!","JPN":"あ、ケイシー！","ENG":"Oh, Kaci!","TWN":"啊，卡西！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"또 혼자 가면 어떡해?","JPN":"また一人で帰ろうとしたの？","ENG":"Why did you go alone?","TWN":"你怎麼又一個人走了？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"수업 끝나면 나랑 같이 다니기로 했잖아.","JPN":"授業が終わったらあたしと一緒に帰ることにしたでしょ？","ENG":"You promised to meet me after class.","TWN":"不是說好了下課後跟我一起走嘛。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"스카이! 너 언제부터 거기 있었어?","JPN":"スカイ！　いつからそこにいたの？","ENG":"Sky! When did you get here?","TWN":"絲凱！你什麼時候站在那兒的？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"아, 너랑 케이시 둘 다 우산 있네? 우리 하나만 빌려 주면 안 돼?","JPN":"あ、スカイとケイシーは傘があるじゃない。一つだけ貸してくれない？","ENG":"Oh, you and Kaci both have an umbrella! Can I borrow one?","TWN":"啊，你跟卡西兩個人都有雨傘啊？借給我們一個吧？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"응! 좋아! 빌려줄게!","JPN":"うん、いいよ！　貸してあげる！","ENG":"Sure! No problem! I'll give you mine!","TWN":"嗯！好！我的借給你們！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"고마워! 내일 돌려 줄게, 스카이!","JPN":"ありがとう！　明日返すからね、スカイ！","ENG":"Thanks, Sky! I'll bring it back tomorrow!","TWN":"謝謝！明天還你，絲凱！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"초코바닐라 우유까지 하나 쳐서!","JPN":"ココアミルクと一緒に！","ENG":"With a carton of chocolate vanilla milk!","TWN":"再加一杯巧克力香草牛奶！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"흠...... 볼수록 신기하단 말이지.","JPN":"ふむ……見ればみるほど不思議なんだよな。","ENG":"Hmm... It's really strange.","TWN":"嗯……越看越覺得神奇。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"너희 둘이 가까이 있으면 스카이의 인식 왜곡 능력이 사라지다니......","JPN":"君たち二人がお互い近くにいるとスカイの認識阻害能力がなくなるなんて……","ENG":"Sky's ability is gone when you two are together...","TWN":"你們兩個靠近後，絲凱的認知扭曲能力居然就消失了……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"말도 안 되는 일인데 정말 그렇게 되잖아?","JPN":"あり得ないことなのに本当にそうなるのがね。","ENG":"It doesn't make sense, but it actually works, right?","TWN":"雖然很不可思議，但事實就是如此啊。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"응! 그야 소원구슬이 이루어 준 소원인걸?","JPN":"うん！　そりゃあ願い玉が叶えてくれた願いなんだからね！","ENG":"Of course, it does! It's the wish granted by the Wishing Ball!","TWN":"嗯！這就是許願珠幫我實現的願望！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"물론 아티펙트인 소원구슬의 힘을 믿지 못하는 건 아니야.","JPN":"もちろん、アーティフィクトの願い玉の力を信じないわけじゃないさ。","ENG":"Oh, I'm not saying I don't believe in the power of the Wishing Ball.","TWN":"當然了，我不是不相信人造神器許願珠的力量。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"하지만 그 원리가 역시 궁금해.","JPN":"でも、その原理がやっぱり気になる。","ENG":"But still, I want to know how it works.","TWN":"不過我真的很想知道原理是什麼。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"케이시와 더듬이의 유대감이 주위에도 특수한 영향을 주도록 만든 걸까?","JPN":"ケイシーとアホ毛ちゃんの絆が周囲にも特殊な影響を与えるようになったのかな？","ENG":"Does the bond between Kaci and Antenna exert a special influence on the surroundings?","TWN":"是讓卡西和小觸角的相處造成連帶，而給周圍造成特殊影響嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"아르티, 우산 없으면 우리랑 같이 쓰고 갈래?","JPN":"アルティ、傘がないならあたしたちと一緒に使おう！","ENG":"Arti, do you wanna go with us? Looks like you don't have an umbrella.","TWN":"阿爾蒂，你沒帶傘的話跟我們一起吧？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"아니, 난 됐어. 오늘은 동아리 연구실에 남을 생각이야.","JPN":"いや、ぼくはいいよ。今日はサークルの研究室に残るつもりでね。","ENG":"No, I'm fine. I'm going to stay late in the lab today.","TWN":"不，不用了，今天我想留在社團研究室。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"운동회는 끝났지만, 아직 너희와 했던 약속을 지켰다곤 할 수 없거든.","JPN":"運動会は終わったけど、まだ君たちとの約束を守ったとは言えない。","ENG":"The Field Day's over, but I haven't fulfilled my promise yet.","TWN":"運動會雖然結束了，但現在我還不能兌現跟你們的約定。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"소원구슬의 원리를 알아낸다면, 더듬이의 문제를 완전히 해결할 수 있을 테니까.","JPN":"願い玉の原理を突き止められたら、アホ毛ちゃんの問題を完全に解決できるはずだから。","ENG":"If I can figure it out how the Wishing Ball works, I should be able to completely solve Antenna's problem.","TWN":"如果能找出許願珠的原理，應該就能徹底解決小觸角的問題了。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"아르티......","JPN":"アルティ……","ENG":"Arti...","TWN":"阿爾蒂……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"내가 뭔가 도와줄 일이 있을까?","JPN":"アルティ……私に何か手伝うことがある？","ENG":"Is there anything I can help with?","TWN":"我能幫上什麼忙嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"당연히 있지. 너는 내 연구에 반드시 필요하다고.","JPN":"当然あるさ。君はぼくの研究に絶対必要なんだ。","ENG":"Of course, there is. I need you for my research.","TWN":"當然能，我的研究可少不了你。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"그러니 우리 동아리에 가입해. 앞으로도 내가 계속 관찰할 수 있도록.","JPN":"だからぼくのサークルに入っておくれよ。これからもぼくがずっと観察できるようにね。","ENG":"Join our club, so that I can keep watching you closely.","TWN":"所以，加入我們社團吧。以後也讓我繼續觀察你。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"응! 그렇게 할게!","JPN":"うん！　そうするよ！","ENG":"Okay! I will!","TWN":"嗯！好的！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"그리고, 힘내! 아르티라면 할 수 있을 거야!","JPN":"これからも頑張ってね！　アルティならできる！","ENG":"And cheer up! I'm sure you can do it!","TWN":"還有，加油！阿爾蒂你一定能做到！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"......그럼 우리도 갈까?","JPN":"……そろそろ、あたしたちも帰ろう？","ENG":"Shall we go now?","TWN":"……那我們也走吧？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"응.","JPN":"うん。","ENG":"Okay.","TWN":"嗯。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L30_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"아, 저기 민들레다! 예쁘게 피었어!","JPN":"あ、あそこを見て、タンポポだよ！　きれいに咲いてる！","ENG":"Oh, look! It's a dandelion! It's lovely!","TWN":"啊，那個是蒲公英！開得真漂亮！"},"stage":{"bg":"SS_SPORTS_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"이건 데이지!","JPN":"これはデイジー！","ENG":"This one is a daisy!","TWN":"這個是雛菊！"},"stage":{"bg":"SS_SPORTS_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"그리고 이건...... 이건 뭐더라?","JPN":"そしてこれは……何だっけ？","ENG":"And this... What was this?","TWN":"還有這個……這個是什麼來著？"},"stage":{"bg":"SS_SPORTS_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"......그건 고사리야.","JPN":"……それはワラビだよ。","ENG":"It's a bracken.","TWN":"……那個是蕨菜。"},"stage":{"bg":"SS_SPORTS_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"와아, 이게 고사리구나! 어떻게 자라는지 궁금해!","JPN":"わぁ、これがワラビか！　どんな環境で育っているのか気になる！","ENG":"Whoa, it's a bracken! I wonder how it grows!","TWN":"哇啊，原來這個是蕨菜啊！好想知道它是怎麼生長的，樣子好微妙啊！"},"stage":{"bg":"SS_SPORTS_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"집에서 기르고 있어. 같이 보러 갈래?","JPN":"家で育てているよ。一緒に見に行く？","ENG":"I grow them at home. Wanna go see them?","TWN":"我在家裡養了一些，你要一起去看看嗎？"},"stage":{"bg":"SS_SPORTS_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"응! 갈래!","JPN":"うん！　行く行く！","ENG":"Yes! I'd love to!","TWN":"嗯！我要去！"},"stage":{"bg":"SS_SPORTS_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"스카이가 와 주면 레오나르도도 기뻐할 거야.","JPN":"スカイが来てくれたらレオナルドもきっと喜ぶね。","ENG":"Leonardo will be happy to see you.","TWN":"絲凱你來的話，萊奧納多肯定也很開心。"},"stage":{"bg":"SS_SPORTS_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"레오나르도......? 레오나르도는 누군데?","JPN":"レオナルド……？　レオナルドって誰？","ENG":"Leonardo? Who's Leonardo?","TWN":"萊奧納多……？萊奧納多是誰？"},"stage":{"bg":"SS_SPORTS_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};